import React from 'react';

export default function AutomataSVG({ automata, type, highlightPath = [] }) {
  if (!automata || !automata.states) {
    return <div style={{ color: '#94a3b8', padding: '20px' }}>No automata generated</div>;
  }

  const states = automata.states;
  const radius = 28;
  const centerX = 300;
  const centerY = 200;
  const circleRadius = 135;

  const positions = {};
  states.forEach((state, i) => {
    const angle = (2 * Math.PI * i) / states.length;
    positions[state] = {
      x: centerX + circleRadius * Math.cos(angle),
      y: centerY + circleRadius * Math.sin(angle),
      index: i
    };
  });

  const accepts = new Set(type === 'nfa' ? [automata.accept] : automata.accepts || []);

  // Group transitions by from/to pairs
  const transitionMap = {};
  Object.entries(automata.transitions || {}).forEach(([from, trans]) => {
    Object.entries(trans).forEach(([symbol, to]) => {
      const destinations = Array.isArray(to) ? to : [to];
      destinations.forEach(dest => {
        const key = `${from}->${dest}`;
        if (!transitionMap[key]) {
          transitionMap[key] = { from, to: dest, symbols: [] };
        }
        if (!transitionMap[key].symbols.includes(symbol)) {
          transitionMap[key].symbols.push(symbol);
        }
      });
    });
  });

  const groupedTransitions = Object.values(transitionMap);

  return (
    <svg width="100%" height="400" viewBox="0 0 600 400" style={{ background: '#060d1a' }}>
      <defs>
        <marker id="arrow" markerWidth="10" markerHeight="10" refX="9" refY="5" orient="auto">
          <path d="M0,0 L10,5 L0,10 Z" fill="#475569" />
        </marker>
      </defs>

      {groupedTransitions.map((t, i) => {
        const from = positions[t.from];
        const to = positions[t.to];
        if (!from || !to) return null;

        const label = t.symbols.join(', ');
        const isHighlighted = highlightPath.includes(t.from) && highlightPath.includes(t.to);
        const color = isHighlighted ? '#f59e0b' : '#475569';

        // 1. Handle Self-Loops
        if (t.from === t.to) {
          const loopPath = `M ${from.x - 10},${from.y - radius} 
                            C ${from.x - 30},${from.y - radius - 40} 
                              ${from.x + 30},${from.y - radius - 40} 
                              ${from.x + 10},${from.y - radius}`;
          return (
            <g key={i}>
              <path d={loopPath} fill="none" stroke={color} strokeWidth="2" markerEnd="url(#arrow)" />
              <text x={from.x} y={from.y - radius - 25} fill="#cbd5e1" fontSize="12" textAnchor="middle" fontWeight="600">{label}</text>
            </g>
          );
        }

        // 2. Calculate Curvature for "Alternative Paths"
        const dx = to.x - from.x;
        const dy = to.y - from.y;
        const dist = Math.sqrt(dx * dx + dy * dy);
        const angle = Math.atan2(dy, dx);
        
        // Determine if they are neighbors in the circle
        const idxDiff = Math.abs(from.index - to.index);
        const isNeighbor = idxDiff === 1 || idxDiff === states.length - 1;
        const reverseExists = groupedTransitions.some(ot => ot.from === t.to && ot.to === t.from);
        
        // If it's a long jump or there's a reverse edge, we curve it to avoid the center
        let curve = 0;
        if (reverseExists) curve = 30;
        else if (!isNeighbor) curve = dist * 0.15; // Bulge out based on distance

        const mx = (from.x + to.x) / 2;
        const my = (from.y + to.y) / 2;
        const nx = -dy / dist; // Normal vector
        const ny = dx / dist;

        const cx = mx + nx * curve;
        const cy = my + ny * curve;

        // Truncate line so it starts/ends at circle boundary
        const startX = from.x + radius * Math.cos(angle + (curve / 100));
        const startY = from.y + radius * Math.sin(angle + (curve / 100));
        const endX = to.x - radius * Math.cos(angle - (curve / 100));
        const endY = to.y - radius * Math.sin(angle - (curve / 100));

        const path = curve === 0 
          ? `M ${startX},${startY} L ${endX},${endY}`
          : `M ${startX},${startY} Q ${cx},${cy} ${endX},${endY}`;

        // Label rotation and placement
        let textRot = angle * (180 / Math.PI);
        if (textRot > 90 || textRot < -90) textRot += 180;
        
        const lx = (curve === 0) ? mx + nx * 12 : mx + nx * (curve + 12);
        const ly = (curve === 0) ? my + ny * 12 : my + ny * (curve + 12);

        return (
          <g key={i}>
            <path d={path} fill="none" stroke={color} strokeWidth="2" markerEnd="url(#arrow)" />
            <text
              transform={`translate(${lx}, ${ly}) rotate(${textRot})`}
              fill="#94a3b8"
              fontSize="11"
              fontWeight="600"
              textAnchor="middle"
              dominantBaseline="central"
            >
              {label}
            </text>
          </g>
        );
      })}

      {states.map(state => {
        const pos = positions[state];
        const isStart = state === automata.start;
        const isAccept = accepts.has(state);
        const isHighlighted = highlightPath.includes(state);

        return (
          <g key={state}>
            <circle
              cx={pos.x}
              cy={pos.y}
              r={radius}
              fill="#0f172a"
              stroke={isHighlighted ? '#f59e0b' : '#334155'}
              strokeWidth="2.5"
            />
            <text
              x={pos.x}
              y={pos.y + 5}
              fill="white"
              fontSize="15"
              fontWeight="700"
              textAnchor="middle"
            >
              {isStart && '-'}{state}{isAccept && '+'}
            </text>
          </g>
        );
      })}
    </svg>
  );
}
